#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char line[1024];
    // consume end of line after T
    fgets(line, sizeof(line), stdin);
    for (int tc = 0; tc < T; ++tc) {
        // read array line (skip possible empty lines)
        do {
            if (!fgets(line, sizeof(line), stdin)) return 0;
        } while (line[0] == '\n' || line[0] == '\r');
        int data[20];
        int m = 0;
        char *token = strtok(line, " \t\n\r");
        while (token) {
            data[m++] = atoi(token);
            token = strtok(NULL, " \t\n\r");
        }
        long long n;
        if (scanf("%lld", &n) != 1) return 0;
        // consume newline after n
        fgets(line, sizeof(line), stdin);
        printf("[");
        for (long long i = 0; i < n; ++i) {
            int val = data[i % m];
            printf("%d", val);
            if (i + 1 < n) printf(", ");
        }
        printf("]\n");
    }
    return 0;
}

