    string dummy;
    getline(cin, dummy); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        string arrLine;
        // skip possible empty lines
        while (getline(cin, arrLine)) {
            if (!arrLine.empty()) break;
        }
        if (arrLine.empty()) break;
        stringstream ss(arrLine);
        vector<long long> data;
        long long x;
        while (ss >> x) data.push_back(x);
        long long n;
        cin >> n;
        getline(cin, dummy); // consume endline after n
        cout << '[';
        size_t m = data.size();
        for (long long i = 0; i < n; ++i) {
            cout << data[i % m];
            if (i + 1 < n) cout << ", ";
        }
        cout << "]\n";
    }
    return 0;
}

