import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        for (int tc = 0; tc < T; ++tc) {
            // read array line, skip empty lines
            String arrLine;
            while ((arrLine = br.readLine()) != null && arrLine.trim().isEmpty()) {}
            if (arrLine == null) break;
            StringTokenizer st = new StringTokenizer(arrLine);
            List<Long> data = new ArrayList<>();
            while (st.hasMoreTokens()) data.add(Long.parseLong(st.nextToken()));
            String nLine = br.readLine();
            while (nLine != null && nLine.trim().isEmpty()) nLine = br.readLine();
            long n = Long.parseLong(nLine.trim());
            StringBuilder sb = new StringBuilder();
            sb.append('[');
            int m = data.size();
            for (long i = 0; i < n; ++i) {
                sb.append(data.get((int)(i % m)));
                if (i + 1 < n) sb.append(", ");
            }
            sb.append(']');
            System.out.println(sb.toString());
        }
    }
}

